def histogram(test):
    """Given a string representing space-separated lowercase letters, return a dictionary
    of the letters with the most occurrences along with their corresponding counts.
    If multiple letters have the same maximum count, return all of them.

    Example:
    histogram('a b c') == {'a': 1, 'b': 1, 'c': 1}
    histogram('a b b a') == {'a': 2, 'b': 2}
    histogram('a b c a b') == {'a': 2, 'b': 2}
    histogram('b b b b a') == {'b': 4}
    histogram('') == {}
    """
    from collections import Counter

    # Split the input string by spaces
    letters = test.split()

    # Count occurrences of each letter
    count = Counter(letters)

    # Find the maximum occurrence count
    if not count:
        return {}

    max_count = max(count.values())

    # Create a dictionary of letters with max occurrences
    result = {letter: cnt for letter, cnt in count.items() if cnt == max_count}

    return result
