def histogram(test):
    """Given a string representing space-separated lowercase letters, return the letter
    that occurs the least along with its corresponding count. If multiple letters have
    the same minimum count, only one will be returned.

    Example:
    histogram('a b c') == {'c': 1}
    histogram('a b b a') == {'a': 2}
    histogram('a b c a b a') == {'b': 2}
    histogram('b b b b a') == {'a': 1}
    histogram('') == {}
    """
    from collections import Counter

    letters = test.split()
    count = Counter(letters)

    if count == {}:
        return {}

    min_count = min(count.values())
    result = next(((letter, cnt) for letter, cnt in count.items() if cnt != min_count), None)

    return {result[0]: result[1]} if result else {}
